#!/usr/bin/env python3
"""
stock-spread dynamic catalog (READ-ONLY).

Builds the `underlying -> per-venue identifier` map from AUTHORITATIVE SOURCES
instead of a hand-maintained ticker list:

  - CEX universe is ENUMERATED from each venue's own instrument list
    (Bybit `symbolType==xstocks`, Gate `currency_pairs` base_name '… xStock',
    Binance `exchangeInfo` validation).
  - The underlying is DERIVED by stripping the venue suffix (xStocks 'X', bStocks 'B').
  - The Solana mint is RESOLVED from Jupiter token search and VERIFIED against the
    Backed issuer authority (freezeAuthority) — a pump.fun look-alike cannot forge it.

Config (`symbology.json`) carries only RULES + issuer-authority constants. The
`underlyings` block is a GENERATED cache (offline determinism for selftests),
regenerated by `--refresh`. No per-ticker hand entry.

Usage:
    python3 catalog.py --refresh           # build live from sources -> rewrite symbology underlyings
    python3 catalog.py --underlying COIN   # resolve a single underlying live (no write)
    python3 catalog.py --selftest          # offline checks (enumerate/derive/verify) exit 0/1

Standard library only. Read-only; no keys.
"""
import json
import os
import sys
import time
from urllib.request import Request, urlopen
from urllib.error import HTTPError

DATA = os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "data", "symbology.json")


def _load():
    with open(DATA, "r") as f:
        return json.load(f)


def _save(doc):
    with open(DATA, "w") as f:
        json.dump(doc, f, indent=2)
        f.write("\n")


def _get(url, timeout=15, retries=2):
    last = None
    for attempt in range(retries + 1):
        try:
            req = Request(url, headers={"User-Agent": "stock-spread/1.0 (read-only)"})
            with urlopen(req, timeout=timeout) as resp:
                return json.loads(resp.read().decode("utf-8"))
        except HTTPError as e:
            last = e
            if e.code == 429 and attempt < retries:
                time.sleep(2 * (attempt + 1))
                continue
            raise
    raise last


def strip_suffix(base, suffix):
    return base[:-len(suffix)] if suffix and base.endswith(suffix) else base


# --- enumerators (pure parse fns take raw, so they're fixture-testable) ---

def parse_bybit_universe(raw, suffix="X"):
    out = {}
    for r in raw["result"]["list"]:
        if r.get("symbolType") == "xstocks":
            out[strip_suffix(r["baseCoin"], suffix)] = r["symbol"]
    return out


def parse_gate_universe(raw, suffix="X"):
    out = {}
    for r in raw:
        if "xStock" in (r.get("base_name") or "") and r.get("trade_status") == "tradable":
            out[strip_suffix(r["base"], suffix)] = r["id"]
    return out


def verify_mint(search_results, underlying, issuer_freeze):
    """Pick the Jupiter result whose symbol is exactly {underlying}x AND whose
    freezeAuthority is the Backed issuer authority. Returns {mint,decimals} or None."""
    want = f"{underlying}x".lower()
    for t in search_results:
        if t.get("symbol", "").lower() == want and t.get("freezeAuthority") == issuer_freeze:
            return {"mint": t["id"], "decimals": t.get("decimals", 8)}
    return None


# --- live fetchers ---

def enumerate_bybit():
    return parse_bybit_universe(_get("https://api.bybit.com/v5/market/instruments-info?category=spot"))


def enumerate_gate():
    return parse_gate_universe(_get("https://api.gateio.ws/api/v4/spot/currency_pairs"))


def binance_trading_symbols():
    raw = _get("https://api.binance.com/api/v3/exchangeInfo")
    return {s["symbol"] for s in raw["symbols"] if s.get("status") == "TRADING"}


def resolve_mint_live(underlying, issuer_freeze):
    raw = _get(f"https://lite-api.jup.ag/tokens/v2/search?query={underlying}x")
    return verify_mint(raw, underlying, issuer_freeze)


def build_catalog(verbose=False):
    cfg = _load()
    rules, auth = cfg["cex_rules"], cfg["issuer_authority"]["xstocks"]
    issuer_freeze = auth["freeze"]
    underlyings = {}

    def add(u, venue, info):
        underlyings.setdefault(u, {"venues": {}})["venues"][venue] = info

    by = enumerate_bybit()
    for u, sym in by.items():
        add(u, "bybit", {"id": sym, "settlement": rules["bybit"]["settlement"], "type": "cex", "verified": True, "live": True, "source": "bybit instruments-info symbolType=xstocks"})
    ga = enumerate_gate()
    for u, pid in ga.items():
        add(u, "gate", {"id": pid, "settlement": rules["gate"]["settlement"], "type": "cex", "verified": True, "live": True, "source": "gate currency_pairs base_name~xStock"})

    bn = binance_trading_symbols()
    for u in list(underlyings):
        sym = rules["binance_bstocks"]["pair"].format(BASE=u + rules["binance_bstocks"]["suffix"])
        if sym in bn:
            add(u, "binance_bstocks", {"id": sym, "settlement": "USDT", "type": "cex", "verified": True, "live": True, "source": "binance exchangeInfo validated"})

    for i, u in enumerate(list(underlyings)):
        if i:
            time.sleep(1)  # be gentle with Jupiter lite-api
        try:
            m = resolve_mint_live(u, issuer_freeze)
        except Exception as e:
            m = None
            if verbose:
                print(f"  mint {u}: error {type(e).__name__}", file=sys.stderr)
        if m:
            add(u, "solana_jupiter", {"id": m["mint"], "decimals": m["decimals"], "settlement": "USDC", "type": "dex", "chain": "solana", "verified": True, "live": True, "source": "jupiter search + issuer-authority verified"})
        if verbose:
            print(f"  {u}: venues={sorted(underlyings[u]['venues'])}", file=sys.stderr)
    return underlyings


# --- offline fixtures for the deterministic gate ---

_FX_BYBIT = {"result": {"list": [
    {"symbol": "TSLAXUSDT", "baseCoin": "TSLAX", "symbolType": "xstocks"},
    {"symbol": "COINXUSDT", "baseCoin": "COINX", "symbolType": "xstocks"},
    {"symbol": "BTCUSDT", "baseCoin": "BTC", "symbolType": "spot"}]}}
_FX_GATE = [
    {"id": "TSLAX_USDT", "base": "TSLAX", "base_name": "Tesla xStock", "trade_status": "tradable"},
    {"id": "BTC_USDT", "base": "BTC", "base_name": "Bitcoin", "trade_status": "tradable"}]
_FX_JUP_GOOD = [{"id": "XsDoVfqeBukxuZHWhdvWHBhgEHjGNst4MLodqsJHzoB", "symbol": "TSLAx", "decimals": 8,
                 "freezeAuthority": "JDq14BWvqCRFNu1krb12bcRpbGtJZ1FLEakMw6FdxJNs"}]
_FX_JUP_SCAM = [{"id": "FAKEmintaddr1111111111111111111111111111111", "symbol": "TSLAx", "decimals": 6,
                 "freezeAuthority": "ScamAuthorityXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX"}]
_ISSUER_FREEZE = "JDq14BWvqCRFNu1krb12bcRpbGtJZ1FLEakMw6FdxJNs"


def _selftest():
    checks = []

    def check(name, cond):
        checks.append((name, bool(cond)))

    check("strip suffix X: NVDAX->NVDA", strip_suffix("NVDAX", "X") == "NVDA")
    check("strip suffix B: TSLAB->TSLA", strip_suffix("TSLAB", "B") == "TSLA")
    check("strip suffix no-op: BTC", strip_suffix("BTC", "X") == "BTC")

    by = parse_bybit_universe(_FX_BYBIT)
    check("bybit enumerate xstocks only", set(by) == {"TSLA", "COIN"})
    check("bybit symbol mapped", by["TSLA"] == "TSLAXUSDT")

    ga = parse_gate_universe(_FX_GATE)
    check("gate enumerate xStock only (no BTC)", set(ga) == {"TSLA"})

    good = verify_mint(_FX_JUP_GOOD, "TSLA", _ISSUER_FREEZE)
    check("mint verify accepts genuine issuer authority", good and good["mint"].startswith("XsDoVf"))
    scam = verify_mint(_FX_JUP_SCAM, "TSLA", _ISSUER_FREEZE)
    check("mint verify REJECTS look-alike (wrong freezeAuthority)", scam is None)
    none = verify_mint([], "TSLA", _ISSUER_FREEZE)
    check("mint verify returns None on no match", none is None)

    failed = [n for n, ok in checks if not ok]
    print(json.dumps({"selftest": "PASS" if not failed else "FAIL", "total": len(checks),
                      "passed": len(checks) - len(failed), "failed": failed}, indent=2))
    return 0 if not failed else 1


def main(argv):
    if "--selftest" in argv:
        return _selftest()
    if "--refresh" in argv:
        cfg = _load()
        underlyings = build_catalog(verbose=True)
        cfg["underlyings"] = dict(sorted(underlyings.items()))
        cfg["_generated_at"] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
        _save(cfg)
        cov = {u: sorted(v["venues"]) for u, v in cfg["underlyings"].items()}
        print(json.dumps({"refreshed": len(cov), "coverage": cov, "generated_at": cfg["_generated_at"]}, indent=2))
        return 0
    if "--underlying" in argv:
        i = argv.index("--underlying")
        u = argv[i + 1].strip().upper()
        cfg = _load()
        auth = cfg["issuer_authority"]["xstocks"]["freeze"]
        venues = {}
        bn = binance_trading_symbols()
        # rule-derive + validate per CEX, then mint
        try:
            gd = _get(f"https://api.gateio.ws/api/v4/spot/currency_pairs/{u}X_USDT")
            if gd.get("trade_status") == "tradable":
                venues["gate"] = {"id": f"{u}X_USDT", "settlement": "USDT", "type": "cex", "verified": True}
        except Exception:
            pass
        try:
            bi = _get(f"https://api.bybit.com/v5/market/instruments-info?category=spot&symbol={u}XUSDT")
            if bi["result"]["list"]:
                venues["bybit"] = {"id": f"{u}XUSDT", "settlement": "USDT", "type": "cex", "verified": True}
        except Exception:
            pass
        if f"{u}BUSDT" in bn:
            venues["binance_bstocks"] = {"id": f"{u}BUSDT", "settlement": "USDT", "type": "cex", "verified": True}
        m = resolve_mint_live(u, auth)
        if m:
            venues["solana_jupiter"] = {"id": m["mint"], "decimals": m["decimals"], "settlement": "USDC", "type": "dex", "chain": "solana", "verified": True}
        print(json.dumps({"underlying": u, "venues": venues}, indent=2))
        return 0
    print(json.dumps({"error": "usage: catalog.py --refresh | --underlying <T> | --selftest"}), file=sys.stderr)
    return 1


if __name__ == "__main__":
    sys.exit(main(sys.argv[1:]))
